class Animal {
  String name;
  Animal(this.name);

  void makeSound() {
    print('Some generic animal sound');
  }
}

class Dog extends Animal {
  Dog(String name) : super(name);

  @override
  void makeSound() {
    print('Woof!');
  }
}

void main() {
  var dog = Dog('Buddy');
  dog.makeSound(); // Woof!
}
